import numpy as np

def dropout(x, p, training):
    if not training:
        return x                       # eval: identity
    mask = (np.random.rand(*x.shape) > p)
    return x * mask / (1.0 - p)        # zero + rescale

def batchnorm(x, gamma, beta, eps=1e-5):
    mu = x.mean(axis=0)
    var = x.var(axis=0)
    x_hat = (x - mu) / np.sqrt(var + eps)
    return gamma * x_hat + beta        # learned rescale

import torch, torch.nn as nn

class Net(nn.Module):
    def __init__(self, d_in=784, h=256, classes=10):
        super().__init__()
        self.fc1 = nn.Linear(d_in, h)
        self.bn1 = nn.BatchNorm1d(h)
        self.drop = nn.Dropout(0.5)
        self.fc2 = nn.Linear(h, classes)

    def forward(self, x):
        x = torch.relu(self.bn1(self.fc1(x)))
        x = self.drop(x)
        return self.fc2(x)
